// src/pages/bank/IssueTokensPage.jsx
import { useState } from "react";
import { useToast } from "../../context/ToastContext";
import PageHeader   from "../../components/shared/PageHeader";
import { banks }    from "../../data/mockData";

const fmt = (n) => n?.toLocaleString() ?? "–";

export default function IssueTokensPage() {
  const toast = useToast();
  const [form, setForm] = useState({ bank:"", amount:"", recipient:"", memo:"" });
  const upd = (k) => (e) => setForm((p) => ({ ...p, [k]: e.target.value }));

  return (
    <div>
      <PageHeader title="Issue Tokens" desc="Mint new donation tokens on the blockchain" />
      <div className="grid-2">
        <div className="card">
          <div className="form-grid section-gap">
            <div className="form-group">
              <label>Issuing Bank</label>
              <select value={form.bank} onChange={upd("bank")}>
                <option value="">Select bank...</option>
                {banks.map((b) => <option key={b.id} value={b.id}>{b.name}</option>)}
              </select>
            </div>
            <div className="form-group"><label>Amount (Tokens)</label><input value={form.amount} onChange={upd("amount")} type="number" placeholder="e.g. 10000" /></div>
            <div className="form-group"><label>Recipient Wallet</label><input value={form.recipient} onChange={upd("recipient")} placeholder="0x..." /></div>
            <div className="form-group"><label>Memo</label><textarea value={form.memo} onChange={upd("memo")} placeholder="Purpose of issuance..." /></div>
            <div className="form-actions">
              <button className="btn btn-secondary">Clear</button>
              <button className="btn btn-primary" onClick={() => toast("Tokens issued successfully", "success")}>Issue Tokens ◈</button>
            </div>
          </div>
        </div>

        <div className="section-gap">
          {banks.map((b) => {
            const pct = Math.round((b.circulating / b.issued) * 100);
            return (
              <div key={b.id} className="stat-card gold">
                <div className="stat-label">{b.name}</div>
                <div className="stat-value gold">{fmt(b.issued)}</div>
                <div style={{ fontSize:11, color:"var(--green)", fontFamily:"'DM Mono',monospace" }}>Circulating: {fmt(b.circulating)}</div>
                <div className="progress-track" style={{ marginTop:8 }}>
                  <div className="progress-fill" style={{ width:`${pct}%` }} />
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}
